async function generateTestPng(
  width: number,
  height: number,
  valueFn: (x: number, y: number) => number,
): Promise<Buffer> {
  const pixels = Buffer.alloc(width * height * 3)
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const i = (y * width + x) * 3
      const val = valueFn(x, y)
      pixels[i] = val; pixels[i + 1] = val; pixels[i + 2] = val
    }
  }
  return sharp(pixels, { raw: { width, height, channels: 3 } }).png().toBuffer()
}

beforeAll(async () => {
  pngA = await generateTestPng(64, 64, (x) => (x < 32 ? 0 : 255))
  pngB = await generateTestPng(64, 64, (_x, y) => (y < 32 ? 0 : 255))
})

WHY: Reduces 26 lines to 16 (helper + 2 calls). The helper name and callback make the split-direction difference immediately visible. This pattern also exists in context-engine phash tests and could be shared as a test utility.

