function createTestOrchestrator(opts: {
  buffers?: Buffer[]; vlmResult?: Partial<VlmResult>;
  intimacyScore?: number; aggregationMs?: number;
} = {}) {
  const screenshotProvider = new SequentialScreenshotProvider(opts.buffers ?? [pngA])
  const vlmProvider = new StubVlmProvider(opts.vlmResult)
  const proactiveEvents: AnimaProactiveEvent[] = []
  const orchestrator = createAnimaOrchestrator(
    { screenshotProvider, vlmProvider },
    { aggregationIntervalMs: opts.aggregationMs ?? 1000,
      initialIntimacyScore: opts.intimacyScore ?? 20,
      onProactiveResponse: (evt) => proactiveEvents.push(evt) },
  )
  return { orchestrator, proactiveEvents, screenshotProvider, vlmProvider }
}

it('fires rest-reminder...', () => {
  const { orchestrator, proactiveEvents } = createTestOrchestrator()
  // ... test body
  orchestrator.stop()
})

WHY: Reduces ~90 lines of test boilerplate to ~15 (helper + 9 one-line calls). Each test clearly shows only its unique configuration via named options. The helper also makes it easy to add new test parameters (e.g., custom triggers) without touching every test.

No change required now. If this config grows beyond 10 fields, consider grouping:

interface AnimaOrchestratorConfig {
  timing?: { screenshotIntervalMs?: number; aggregationIntervalMs?: number; ... }
  persona?: { triggers?: readonly TriggerCondition[]; initialIntimacyScore?: number }
  onProactiveResponse?: (event: AnimaProactiveEvent) => void
  onError?: (error: Error) => void
}

WHY: Preemptive structural note. The current flat config is acceptable for 8 fields but is approaching the threshold where grouping improves navigability.
